import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  KanbanSquare, 
  DollarSign, 
  MousePointerClick, 
  RefreshCw, 
  Database, 
  AlertCircle, 
  Plus, 
  CheckCircle2, 
  Clock, 
  TrendingUp, 
  ChevronRight, 
  Sparkles, 
  HelpCircle, 
  Trash2, 
  Lock, 
  LogOut, 
  User, 
  Sliders, 
  FileSpreadsheet, 
  Calendar, 
  Layers, 
  Globe, 
  Bell,
  Coins,
  Hourglass,
  ChevronDown,
  ChevronUp,
  Sun,
  Moon
} from 'lucide-react';

// === CONSTANTS & UTILS ===
const STORAGE_KEY = 'agencyos_pro_data';
const TASK_PRESETS = [
  { id: 'pr_web', label: 'Bikin Web (60 Menit)', rate: 1000000, minutes: 60 },
  { id: 'pr_domain', label: 'Cari Domain (15 Menit)', rate: 50000, minutes: 15 },
  { id: 'pr_ads', label: 'Riset Iklan (30 Menit)', rate: 150000, minutes: 30 },
  { id: 'pr_design', label: 'Desain UI/UX (45 Menit)', rate: 400000, minutes: 45 }
];

const generateId = () => `${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
const formatRupiah = (num) => new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', minimumFractionDigits: 0 }).format(num);

// === INITIAL DATA ===
const getInitialData = () => {
  const saved = localStorage.getItem(STORAGE_KEY);
  if (saved) {
    try {
      return JSON.parse(saved);
    } catch (e) {
      console.error('Failed to parse saved data', e);
    }
  }
  
  return {
    clients: [
      { id: 'c1', name: 'Budi Santoso', company: 'PT Maju Bersama', email: 'budi@majubersama.com', phone: '0812-3456-7890', website: 'https://majubersama.com', status: 'Aktif', totalDeal: 25000000, paidAmount: 15000000, clicks: 342, createdAt: '2026-01-15' },
      { id: 'c2', name: 'Siti Rahma', company: 'CV Berkah Abadi', email: 'siti@berkahabadi.co.id', phone: '0813-9876-5432', website: 'https://berkahabadi.co.id', status: 'Aktif', totalDeal: 18000000, paidAmount: 18000000, clicks: 128, createdAt: '2026-02-10' },
      { id: 'c3', name: 'Andi Wijaya', company: 'Toko Elektronik Kita', email: 'andi@tokokita.com', phone: '0857-1122-3344', website: 'https://tokokita.com', status: 'Kritis', totalDeal: 45000000, paidAmount: 10000000, clicks: 890, createdAt: '2026-01-20' }
    ],
    projects: [
      { id: 'p1', name: 'Rebranding & Web Corporate', clientId: 'c1', progress: 65, status: 'Sedang Berjalan', value: 25000000, month: '2026-06', createdAt: '2026-05-01' },
      { id: 'p2', name: 'Sistem Inventory Toko', clientId: 'c3', progress: 20, status: 'Harus Dikerjakan', value: 45000000, month: '2026-06', createdAt: '2026-05-15' },
      { id: 'p3', name: 'E-Commerce Website Update', clientId: 'c2', progress: 100, status: 'Selesai', value: 18000000, month: '2026-06', createdAt: '2026-04-10' }
    ],
    tasks: [
      { id: 't1', title: 'Setup Hosting & Domain Klien', projectId: 'p1', priority: 'Tinggi', status: 'Prioritas Utama', dueDate: '2026-06-20', assignedTo: 'Nasir', executorFee: 500000, timeSpent: 30, completedAt: null, taskType: 'Domain', createdAt: '2026-06-01' },
      { id: 't2', title: 'Desain Wireframe & UI/UX Landing Page', projectId: 'p1', priority: 'Sedang', status: 'Sedang Berjalan', dueDate: '2026-06-25', assignedTo: 'Nikita', executorFee: 400000, timeSpent: 45, completedAt: null, taskType: 'Desain', createdAt: '2026-06-02' },
      { id: 't3', title: 'Mencari Domain & Name Server Terbaik', projectId: 'p1', priority: 'Tinggi', status: 'Harus Dikerjakan', dueDate: '2026-06-18', assignedTo: null, executorFee: 50000, timeSpent: 15, completedAt: null, taskType: 'Domain', createdAt: '2026-06-05' },
      { id: 't4', title: 'Slicing Frontend & Integrasi Database', projectId: 'p3', priority: 'Tinggi', status: 'Selesai', dueDate: '2026-06-10', assignedTo: 'Nikita', executorFee: 1000000, timeSpent: 60, completedAt: '2026-06-12', taskType: 'Web', createdAt: '2026-06-01' }
    ],
    domains: [
      { id: 'd1', domainName: 'majubersama.com', expiryDate: '2026-07-15', provider: 'Niagahoster', clicks: 342, createdAt: '2026-01-01' },
      { id: 'd2', domainName: 'tokokita.com', expiryDate: '2026-06-28', provider: 'Domainesia', clicks: 890, createdAt: '2026-01-01' }
    ],
    team: [
      { id: 'tm1', name: 'Nasir', role: 'Maker', email: 'nasir@agency.com', phone: '08123456789', joinDate: '2025-01-01', totalTasksCompleted: 45, totalEarnings: 15000000 },
      { id: 'tm2', name: 'Nikita', role: 'Executor', email: 'nikita@agency.com', phone: '081298765432', joinDate: '2025-06-01', totalTasksCompleted: 32, totalEarnings: 12500000 },
      { id: 'tm3', name: 'Bambang', role: 'Executor', email: 'bambang@agency.com', phone: '081355577788', joinDate: '2026-01-15', totalTasksCompleted: 12, totalEarnings: 3500000 }
    ],
    activityLog: []
  };
};

export default function App() {
  // Authentication
  const [user, setUser] = useState(null);
  const [loginNameInput, setLoginNameInput] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  
  // Data State
  const [clients, setClients] = useState([]);
  const [projects, setProjects] = useState([]);
  const [tasks, setTasks] = useState([]);
  const [domains, setDomains] = useState([]);
  const [team, setTeam] = useState([]);
  const [activityLog, setActivityLog] = useState([]);
  
  // UI State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedMonth, setSelectedMonth] = useState('Semua');
  const [showToast, setShowToast] = useState(null);
  const [showNotifDropdown, setShowNotifDropdown] = useState(false);
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [darkMode, setDarkMode] = useState(true);
  const [globalSearch, setGlobalSearch] = useState('');
  const [showSearchResults, setShowSearchResults] = useState(false);
  
  // Modal States
  const [showAddClient, setShowAddClient] = useState(false);
  const [showAddProject, setShowAddProject] = useState(false);
  const [showAddTask, setShowAddTask] = useState(false);
  const [showAddDomain, setShowAddDomain] = useState(false);
  const [showAddTeamMember, setShowAddTeamMember] = useState(false);
  const [deleteConfirmation, setDeleteConfirmation] = useState({ show: false, type: '', id: '', name: '' });
  
  // Form States
  const [newClient, setNewClient] = useState({ name: '', company: '', email: '', phone: '', website: '', status: 'Aktif', totalDeal: '', paidAmount: '' });
  const [newProject, setNewProject] = useState({ name: '', clientId: '', progress: 0, status: 'Harus Dikerjakan', value: '', month: new Date().toISOString().slice(0, 7) });
  const [newTask, setNewTask] = useState({ title: '', projectId: '', priority: 'Sedang', status: 'Harus Dikerjakan', dueDate: '', executorFee: 50000, timeSpent: 15, taskType: 'Domain' });
  const [newDomain, setNewDomain] = useState({ domainName: '', expiryDate: '', provider: '' });
  const [newTeamMember, setNewTeamMember] = useState({ name: '', role: 'Executor', email: '', phone: '' });
  
  // Claim Task State
  const [claimingTaskId, setClaimingTaskId] = useState(null);
  const [minutesSpentInput, setMinutesSpentInput] = useState('');
  const [claimRewardValue, setClaimRewardValue] = useState(0);
  
  // AI Analysis State
  const [aiAnalysis, setAiAnalysis] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Load data from localStorage on mount
  useEffect(() => {
    const data = getInitialData();
    setClients(data.clients);
    setProjects(data.projects);
    setTasks(data.tasks);
    setDomains(data.domains);
    setTeam(data.team);
    setActivityLog(data.activityLog || []);
  }, []);

  // Save data to localStorage
  useEffect(() => {
    if (clients.length || projects.length || tasks.length) {
      const dataToSave = { clients, projects, tasks, domains, team, activityLog };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
    }
  }, [clients, projects, tasks, domains, team, activityLog]);

  // Add activity log helper
  const addActivityLog = useCallback((action, details) => {
    const newLog = {
      id: generateId(),
      action,
      details,
      user: user?.name || 'System',
      timestamp: new Date().toISOString(),
      userRole: user?.role || 'System'
    };
    setActivityLog(prev => [newLog, ...prev].slice(0, 100));
  }, [user]);

  // Toast helper
  const triggerToast = useCallback((message, type = 'success') => {
    setShowToast({ message, type });
    setTimeout(() => setShowToast(null), 4000);
  }, []);

  // Login handler
  const handleLogin = useCallback((e) => {
    e.preventDefault();
    const trimmed = loginNameInput.trim();
    if (!trimmed) return;

    if (trimmed.toLowerCase() === 'nasir' && loginPassword === 'admin123') {
      setUser({ name: 'Nasir', role: 'Maker', email: 'nasir@agency.com' });
      triggerToast('Selamat Datang Nasir!', 'success');
      addActivityLog('LOGIN', 'Maker login successful');
    } else if (team.some(m => m.name.toLowerCase() === trimmed.toLowerCase())) {
      const member = team.find(m => m.name.toLowerCase() === trimmed.toLowerCase());
      setUser({ name: member.name, role: member.role, email: member.email });
      triggerToast(`Halo ${member.name}, selamat bekerja!`, 'success');
      addActivityLog('LOGIN', `${member.name} logged in`);
    } else {
      triggerToast('Username atau password salah!', 'error');
    }
  }, [loginNameInput, loginPassword, team, triggerToast, addActivityLog]);

  // Logout
  const handleLogout = useCallback(() => {
    addActivityLog('LOGOUT', `${user?.name} logged out`);
    setUser(null);
    setLoginNameInput('');
    setLoginPassword('');
    triggerToast('Keluar sistem berhasil.', 'info');
  }, [user, addActivityLog, triggerToast]);

  // Delete confirmation
  const confirmDelete = (type, id, name) => {
    setDeleteConfirmation({ show: true, type, id, name });
  };

  const executeDelete = () => {
    const { type, id } = deleteConfirmation;
    switch (type) {
      case 'client':
        setClients(prev => prev.filter(c => c.id !== id));
        addActivityLog('DELETE_CLIENT', `Deleted client: ${deleteConfirmation.name}`);
        triggerToast('Klien berhasil dihapus');
        break;
      case 'project':
        setProjects(prev => prev.filter(p => p.id !== id));
        addActivityLog('DELETE_PROJECT', `Deleted project: ${deleteConfirmation.name}`);
        triggerToast('Proyek berhasil dihapus');
        break;
      case 'task':
        setTasks(prev => prev.filter(t => t.id !== id));
        addActivityLog('DELETE_TASK', `Deleted task: ${deleteConfirmation.name}`);
        triggerToast('Tugas berhasil dihapus');
        break;
      case 'domain':
        setDomains(prev => prev.filter(d => d.id !== id));
        addActivityLog('DELETE_DOMAIN', `Deleted domain: ${deleteConfirmation.name}`);
        triggerToast('Domain berhasil dihapus');
        break;
      default:
        break;
    }
    setDeleteConfirmation({ show: false, type: '', id: '', name: '' });
  };

  // CRUD Handlers
  const handleAddClientSubmit = useCallback((e) => {
    e.preventDefault();
    const added = {
      ...newClient,
      id: generateId(),
      totalDeal: Number(newClient.totalDeal) || 0,
      paidAmount: Number(newClient.paidAmount) || 0,
      clicks: 0,
      createdAt: new Date().toISOString().slice(0, 10)
    };
    setClients(prev => [...prev, added]);
    addActivityLog('ADD_CLIENT', `Added client: ${added.company}`);
    setShowAddClient(false);
    triggerToast(`Klien "${newClient.company}" ditambahkan!`);
    setNewClient({ name: '', company: '', email: '', phone: '', website: '', status: 'Aktif', totalDeal: '', paidAmount: '' });
  }, [newClient, addActivityLog, triggerToast]);

  const handleAddProjectSubmit = useCallback((e) => {
    e.preventDefault();
    const added = {
      ...newProject,
      id: generateId(),
      progress: Number(newProject.progress) || 0,
      value: Number(newProject.value) || 0,
      createdAt: new Date().toISOString().slice(0, 10)
    };
    setProjects(prev => [...prev, added]);
    addActivityLog('ADD_PROJECT', `Added project: ${added.name}`);
    setShowAddProject(false);
    triggerToast(`Proyek "${newProject.name}" ditambahkan!`);
    setNewProject({ name: '', clientId: clients[0]?.id || '', progress: 0, status: 'Harus Dikerjakan', value: '', month: new Date().toISOString().slice(0, 7) });
  }, [newProject, clients, addActivityLog, triggerToast]);

  const handleAddTaskSubmit = useCallback((e) => {
    e.preventDefault();
    const added = {
      ...newTask,
      id: generateId(),
      assignedTo: null,
      completedAt: null,
      executorFee: Number(newTask.executorFee) || 0,
      timeSpent: Number(newTask.timeSpent) || 15,
      createdAt: new Date().toISOString().slice(0, 10)
    };
    setTasks(prev => [...prev, added]);
    addActivityLog('ADD_TASK', `Added task: ${added.title}`);
    setShowAddTask(false);
    triggerToast(`Tugas berhasil dibuat! Selesai dapat ${formatRupiah(added.executorFee)}`);
    setNewTask({ title: '', projectId: projects[0]?.id || '', priority: 'Sedang', status: 'Harus Dikerjakan', dueDate: '', executorFee: 50000, timeSpent: 15, taskType: 'Domain' });
  }, [newTask, projects, addActivityLog, triggerToast]);

  const handleAddDomainSubmit = useCallback((e) => {
    e.preventDefault();
    const added = {
      ...newDomain,
      id: generateId(),
      clicks: 0,
      createdAt: new Date().toISOString().slice(0, 10)
    };
    setDomains(prev => [...prev, added]);
    addActivityLog('ADD_DOMAIN', `Added domain: ${added.domainName}`);
    setShowAddDomain(false);
    triggerToast(`Domain "${newDomain.domainName}" dipantau.`);
    setNewDomain({ domainName: '', expiryDate: '', provider: '' });
  }, [newDomain, addActivityLog, triggerToast]);

  const handleAddTeamMemberSubmit = useCallback((e) => {
    e.preventDefault();
    const added = {
      id: generateId(),
      ...newTeamMember,
      joinDate: new Date().toISOString().slice(0, 10),
      totalTasksCompleted: 0,
      totalEarnings: 0
    };
    setTeam(prev => [...prev, added]);
    addActivityLog('ADD_TEAM', `Added team member: ${added.name}`);
    setShowAddTeamMember(false);
    triggerToast(`Anggota tim "${newTeamMember.name}" ditambahkan!`);
    setNewTeamMember({ name: '', role: 'Executor', email: '', phone: '' });
  }, [newTeamMember, addActivityLog, triggerToast]);

  const handleClaimTask = useCallback((taskId) => {
    setTasks(prev => prev.map(t => {
      if (t.id === taskId && !t.assignedTo) {
        addActivityLog('CLAIM_TASK', `${user?.name} claimed task: ${t.title}`);
        triggerToast(`Tugas "${t.title}" diambil! Segera kerjakan.`);
        return { ...t, assignedTo: user?.name, status: 'Sedang Berjalan' };
      }
      return t;
    }));
  }, [user, addActivityLog, triggerToast]);

  const openCompleteTaskDialog = useCallback((taskId) => {
    const task = tasks.find(t => t.id === taskId);
    if (task && task.assignedTo === user?.name) {
      setClaimingTaskId(taskId);
      setMinutesSpentInput(String(task.timeSpent));
      setClaimRewardValue(task.executorFee);
    } else {
      triggerToast('Hanya yang mengerjakan yang bisa klaim!', 'error');
    }
  }, [tasks, user, triggerToast]);

  const handleCompleteTaskSubmit = useCallback((e) => {
    e.preventDefault();
    const mins = Number(minutesSpentInput) || 15;
    setTasks(prev => prev.map(t => {
      if (t.id === claimingTaskId) {
        addActivityLog('COMPLETE_TASK', `${user?.name} completed task: ${t.title} in ${mins} minutes`);
        setTeam(prevTeam => prevTeam.map(m => {
          if (m.name === user?.name) {
            return {
              ...m,
              totalTasksCompleted: (m.totalTasksCompleted || 0) + 1,
              totalEarnings: (m.totalEarnings || 0) + claimRewardValue
            };
          }
          return m;
        }));
        triggerToast(`Kerja bagus! ${formatRupiah(claimRewardValue)} masuk akun Anda!`, 'success');
        return { 
          ...t, 
          status: 'Selesai', 
          timeSpent: mins, 
          executorFee: claimRewardValue,
          completedAt: new Date().toISOString().slice(0, 10) 
        };
      }
      return t;
    }));
    setClaimingTaskId(null);
  }, [claimingTaskId, minutesSpentInput, claimRewardValue, user, addActivityLog, triggerToast]);

  const handleProjectProgressChange = useCallback((projectId, val) => {
    setProjects(prev => prev.map(p => {
      if (p.id === projectId) {
        const nextStatus = val >= 100 ? 'Selesai' : (val > 0 ? 'Sedang Berjalan' : 'Harus Dikerjakan');
        return { ...p, progress: Number(val), status: nextStatus };
      }
      return p;
    }));
  }, []);

  const selectPresetForNewTask = useCallback((presetId) => {
    const preset = TASK_PRESETS.find(p => p.id === presetId);
    if (preset) {
      setNewTask({
        ...newTask,
        timeSpent: preset.minutes,
        executorFee: preset.rate,
        taskType: preset.id === 'pr_web' ? 'Web' : preset.id === 'pr_domain' ? 'Domain' : 'Riset'
      });
    }
  }, [newTask]);

  // Stats Calculations
  const stats = useMemo(() => {
    const filteredProjects = selectedMonth === 'Semua' 
      ? projects 
      : projects.filter(p => p.month === selectedMonth);

    const projectIds = filteredProjects.map(p => p.id);
    const filteredTasks = selectedMonth === 'Semua'
      ? tasks
      : tasks.filter(t => projectIds.includes(t.projectId));

    const totalDeals = filteredProjects.reduce((sum, p) => sum + Number(p.value || 0), 0);
    const totalEarnings = clients.reduce((sum, c) => sum + Number(c.paidAmount || 0), 0);
    const totalExecutorFees = filteredTasks.reduce((sum, t) => t.status === 'Selesai' ? sum + Number(t.executorFee || 0) : sum, 0);
    const profit = totalEarnings - totalExecutorFees;
    const taskAvailableCount = filteredTasks.filter(t => t.status !== 'Selesai').length;
    const taskCompletedCount = filteredTasks.filter(t => t.status === 'Selesai').length;
    const totalClicks = clients.reduce((sum, c) => sum + Number(c.clicks || 0), 0);
    const overdueTasks = tasks.filter(t => t.status !== 'Selesai' && t.dueDate && new Date(t.dueDate) < new Date()).length;
    
    const leaderboard = [...team].sort((a, b) => (b.totalEarnings || 0) - (a.totalEarnings || 0));
    
    const monthlyTrend = {};
    tasks.filter(t => t.status === 'Selesai' && t.completedAt).forEach(t => {
      const month = t.completedAt.slice(0, 7);
      monthlyTrend[month] = (monthlyTrend[month] || 0) + (t.executorFee || 0);
    });

    return {
      totalDeals,
      totalEarnings,
      totalExecutorFees,
      profit,
      taskAvailableCount,
      taskCompletedCount,
      totalClicks,
      overdueTasks,
      leaderboard,
      monthlyTrend: Object.entries(monthlyTrend).slice(-6)
    };
  }, [clients, projects, tasks, team, selectedMonth]);

  // Notifications
  const notifications = useMemo(() => {
    const list = [];
    const today = new Date();

    tasks.forEach(t => {
      if (t.status !== 'Selesai' && t.dueDate) {
        const dueDate = new Date(t.dueDate);
        const diffDays = Math.ceil((dueDate - today) / (1000 * 60 * 60 * 24));

        if (diffDays < 0) {
          list.push({
            id: `notif-overdue-${t.id}`,
            type: 'danger',
            title: 'TUGAS LEWAT DEADLINE!',
            message: `Tugas "${t.title}" telah terlambat ${Math.abs(diffDays)} hari.`,
          });
        } else if (diffDays <= 3) {
          list.push({
            id: `notif-urgent-${t.id}`,
            type: 'warning',
            title: 'Tugas Hampir Jatuh Tempo',
            message: `Sisa ${diffDays} hari lagi untuk menyelesaikan "${t.title}".`,
          });
        }
      }
    });

    domains.forEach(d => {
      const expiry = new Date(d.expiryDate);
      const diffDays = Math.ceil((expiry - today) / (1000 * 60 * 60 * 24));
      if (diffDays <= 30 && diffDays > 0) {
        list.push({
          id: `notif-domain-${d.id}`,
          type: 'danger',
          title: 'Domain Mau Habis!',
          message: `${d.domainName} kedaluwarsa ${diffDays} hari lagi.`,
        });
      }
    });

    return list;
  }, [tasks, domains]);

  const availableMonths = useMemo(() => {
    const months = new Set(projects.map(p => p.month));
    return ['Semua', ...Array.from(months).sort()];
  }, [projects]);

  // Global Search Results
  const searchResults = useMemo(() => {
    if (!globalSearch.trim()) return { clients: [], projects: [], tasks: [] };
    const query = globalSearch.toLowerCase();
    return {
      clients: clients.filter(c => c.name.toLowerCase().includes(query) || c.company.toLowerCase().includes(query)),
      projects: projects.filter(p => p.name.toLowerCase().includes(query)),
      tasks: tasks.filter(t => t.title.toLowerCase().includes(query))
    };
  }, [globalSearch, clients, projects, tasks]);

  // Login Screen
  if (!user) {
    return (
      <div className={`min-h-screen ${darkMode ? 'bg-slate-900 text-slate-100' : 'bg-gray-50 text-gray-900'} flex items-center justify-center p-4`}>
        <div className={`${darkMode ? 'bg-slate-950 border-slate-800' : 'bg-white border-gray-200'} border rounded-2xl p-8 max-w-sm w-full shadow-2xl space-y-6`}>
          <div className="text-center space-y-2">
            <div className="inline-flex p-3.5 bg-indigo-600/10 text-indigo-400 rounded-2xl">
              <Coins size={30} />
            </div>
            <h1 className="text-xl font-black">AgencyOS Pro</h1>
            <p className="text-xs text-slate-400">Sistem Kendali Kerja & Profit Instan</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input type="text" required placeholder="Nama" value={loginNameInput} onChange={(e) => setLoginNameInput(e.target.value)} className={`w-full p-3 rounded-lg border ${darkMode ? 'bg-slate-900 border-slate-700 text-white' : 'bg-gray-100 border-gray-300'}`} />
            <input type="password" required placeholder="Password" value={loginPassword} onChange={(e) => setLoginPassword(e.target.value)} className={`w-full p-3 rounded-lg border ${darkMode ? 'bg-slate-900 border-slate-700 text-white' : 'bg-gray-100 border-gray-300'}`} />
            <button type="submit" className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-3 rounded-lg transition-all">Masuk</button>
          </form>
          <p className="text-[10px] text-center text-slate-500">Demo: nasir / admin123</p>
        </div>
      </div>
    );
  }

  // Main App
  return (
    <div className={`min-h-screen ${darkMode ? 'bg-slate-900 text-slate-100' : 'bg-gray-50 text-gray-900'}`}>
      {/* Toast */}
      {showToast && (
        <div className={`fixed bottom-6 right-6 z-50 p-4 rounded-xl shadow-2xl border flex items-center gap-3 animate-fadeIn text-sm font-semibold ${
          showToast.type === 'success' ? (darkMode ? 'bg-emerald-950/90 border-emerald-500/40 text-emerald-400' : 'bg-emerald-100 border-emerald-500 text-emerald-700') : 
          (darkMode ? 'bg-rose-950/90 border-rose-500/40 text-rose-400' : 'bg-rose-100 border-rose-500 text-rose-700')
        }`}>
          <span className="w-1.5 h-1.5 rounded-full bg-current animate-ping"></span>
          <span>{showToast.message}</span>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {deleteConfirmation.show && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className={`${darkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-gray-200'} border rounded-xl max-w-sm w-full p-6 space-y-5`}>
            <div className="text-center">
              <div className="mx-auto w-12 h-12 bg-rose-500/10 rounded-full flex items-center justify-center mb-4">
                <Trash2 className="text-rose-500" size={24} />
              </div>
              <h3 className="text-lg font-black mb-2">Konfirmasi Hapus</h3>
              <p className="text-sm text-slate-400">Hapus "{deleteConfirmation.name}"? Tindakan ini tidak dapat dibatalkan.</p>
            </div>
            <div className="flex gap-3">
              <button onClick={() => setDeleteConfirmation({ show: false, type: '', id: '', name: '' })} className="flex-1 py-2 bg-slate-700 rounded-lg font-bold">Batal</button>
              <button onClick={executeDelete} className="flex-1 py-2 bg-rose-600 hover:bg-rose-500 rounded-lg font-bold">Hapus</button>
            </div>
          </div>
        </div>
      )}

      {/* Sidebar */}
      <aside className={`fixed left-0 top-0 h-full ${sidebarCollapsed ? 'w-20' : 'w-64'} ${darkMode ? 'bg-slate-950 border-slate-800' : 'bg-white border-gray-200'} border-r transition-all duration-300 z-20 flex flex-col`}>
        <div className={`p-5 border-b ${darkMode ? 'border-slate-800' : 'border-gray-200'} flex items-center justify-between`}>
          {!sidebarCollapsed && (
            <div className="flex items-center gap-3">
              <div className="p-2 bg-indigo-600 rounded-lg text-white"><Layers size={18} /></div>
              <div><h1 className="font-extrabold">AgencyOS</h1><p className="text-[10px] text-indigo-400">Workspace</p></div>
            </div>
          )}
          {sidebarCollapsed && <div className="p-2 bg-indigo-600 rounded-lg text-white mx-auto"><Layers size={18} /></div>}
          <button onClick={() => setSidebarCollapsed(!sidebarCollapsed)} className="p-1 rounded-lg hover:bg-slate-800">
            {sidebarCollapsed ? <ChevronRight size={16} /> : <ChevronDown size={16} />}
          </button>
        </div>

        <div className={`p-4 mx-3 my-3 ${darkMode ? 'bg-slate-900/60 border-slate-800/60' : 'bg-gray-100 border-gray-300'} border rounded-xl`}>
          <div className="flex items-center justify-between">
            <div>
              <p className="text-[9px] text-slate-500">Karyawan</p>
              <p className="text-sm font-black">{user.name}</p>
              <span className={`inline-flex text-[9px] font-bold px-1.5 py-0.5 rounded mt-1 ${user.role === 'Maker' ? 'bg-indigo-500/10 text-indigo-400' : 'bg-emerald-500/10 text-emerald-400'}`}>{user.role}</span>
            </div>
            <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-rose-400 rounded-lg"><LogOut size={16} /></button>
          </div>
        </div>

        <nav className="flex-1 p-3 space-y-1">
          {['dashboard', 'clients', 'projects', 'tasks', 'finance', 'domains'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-semibold transition-all ${activeTab === tab ? 'bg-indigo-600/20 text-indigo-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'} ${sidebarCollapsed ? 'justify-center' : ''}`}>
              {tab === 'dashboard' && <LayoutDashboard size={18} />}
              {tab === 'clients' && <Users size={18} />}
              {tab === 'projects' && <Sliders size={18} />}
              {tab === 'tasks' && <KanbanSquare size={18} />}
              {tab === 'finance' && <DollarSign size={18} />}
              {tab === 'domains' && <Globe size={18} />}
              {!sidebarCollapsed && <span>{tab === 'dashboard' ? 'Dashboard' : tab === 'clients' ? 'Klien' : tab === 'projects' ? 'Proyek' : tab === 'tasks' ? 'Task Board' : tab === 'finance' ? 'Keuangan' : 'Domain'}</span>}
            </button>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className={`transition-all duration-300 ${sidebarCollapsed ? 'ml-20' : 'ml-64'} p-6`}>
        {/* Header with Search */}
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 mb-6">
          <div>
            <h2 className="text-xl font-black">
              {activeTab === 'dashboard' && 'Dashboard'}
              {activeTab === 'clients' && 'Manajemen Klien'}
              {activeTab === 'projects' && 'Proyek'}
              {activeTab === 'tasks' && 'Task Board'}
              {activeTab === 'finance' && 'Keuangan'}
              {activeTab === 'domains' && 'Domain'}
            </h2>
            <p className="text-xs text-slate-400">{new Date().toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
          </div>
          
          <div className="flex items-center gap-3 w-full lg:w-auto">
            <div className="relative flex-1 lg:w-64">
              <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
              <input type="text" value={globalSearch} onChange={(e) => setGlobalSearch(e.target.value)} placeholder="Cari..." className={`w-full pl-9 pr-4 py-2 rounded-lg border ${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-gray-100 border-gray-300'} outline-none focus:border-indigo-500`} />
            </div>
            <button onClick={() => setDarkMode(!darkMode)} className={`p-2 rounded-lg border ${darkMode ? 'border-slate-700' : 'border-gray-300'}`}>
              {darkMode ? <Sun size={18} /> : <Moon size={18} />}
            </button>
            <div className="relative">
              <button onClick={() => setShowNotifDropdown(!showNotifDropdown)} className={`p-2 rounded-lg border relative ${darkMode ? 'border-slate-700' : 'border-gray-300'}`}>
                <Bell size={18} />
                {notifications.length > 0 && <span className="absolute -top-1 -right-1 w-5 h-5 bg-rose-600 text-white rounded-full text-[10px] font-bold flex items-center justify-center">{notifications.length}</span>}
              </button>
              {showNotifDropdown && (
                <div className={`absolute right-0 mt-3 w-80 ${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-gray-200'} border rounded-xl shadow-2xl z-50`}>
                  <div className="p-3 border-b border-slate-700 font-bold text-xs">Notifikasi ({notifications.length})</div>
                  <div className="max-h-64 overflow-y-auto">
                    {notifications.map(n => (
                      <div key={n.id} className="p-3 border-b border-slate-700 text-xs">
                        <p className="font-bold text-rose-400">{n.title}</p>
                        <p className="text-slate-400">{n.message}</p>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Dashboard */}
        {activeTab === 'dashboard' && (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className={`p-5 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                <p className="text-xs text-slate-400">Laba Bersih</p>
                <p className="text-2xl font-bold text-emerald-400">{formatRupiah(stats.profit)}</p>
              </div>
              <div className={`p-5 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                <p className="text-xs text-slate-400">Total Fee Tim</p>
                <p className="text-2xl font-bold text-amber-400">{formatRupiah(stats.totalExecutorFees)}</p>
              </div>
              <div className={`p-5 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                <p className="text-xs text-slate-400">Tugas Tersedia</p>
                <p className="text-2xl font-bold text-indigo-400">{stats.taskAvailableCount}</p>
              </div>
              <div className={`p-5 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                <p className="text-xs text-slate-400">Total Klik</p>
                <p className="text-2xl font-bold text-sky-400">{stats.totalClicks.toLocaleString()}</p>
              </div>
            </div>

            <div className={`p-5 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
              <h3 className="font-bold mb-3">Tugas Mendesak</h3>
              <div className="space-y-2">
                {tasks.filter(t => t.status !== 'Selesai' && t.dueDate).slice(0, 5).map(task => (
                  <div key={task.id} className="flex justify-between items-center p-3 bg-slate-700/30 rounded-lg">
                    <div>
                      <p className="font-semibold">{task.title}</p>
                      <p className="text-xs text-slate-400">Due: {task.dueDate}</p>
                    </div>
                    <span className="text-emerald-400 font-bold">{formatRupiah(task.executorFee)}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Clients */}
        {activeTab === 'clients' && (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="font-bold text-lg">Daftar Klien</h3>
              {user.role === 'Maker' && (
                <button onClick={() => setShowAddClient(true)} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg text-sm font-bold">
                  <Plus size={14} /> Tambah Klien
                </button>
              )}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {clients.map(client => (
                <div key={client.id} className={`p-4 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-bold">{client.company}</h4>
                      <p className="text-sm text-slate-400">{client.name}</p>
                    </div>
                    <span className={`px-2 py-0.5 rounded text-xs ${client.status === 'Aktif' ? 'bg-emerald-500/20 text-emerald-400' : 'bg-rose-500/20 text-rose-400'}`}>{client.status}</span>
                  </div>
                  <div className="mt-3 text-sm space-y-1">
                    <p>📧 {client.email}</p>
                    <p>📱 {client.phone}</p>
                    <p>💰 Deal: {formatRupiah(client.totalDeal)}</p>
                    <p>💵 Terbayar: {formatRupiah(client.paidAmount)}</p>
                  </div>
                  {user.role === 'Maker' && (
                    <div className="flex justify-end mt-3 pt-2 border-t border-slate-700">
                      <button onClick={() => confirmDelete('client', client.id, client.company)} className="p-1 text-rose-400 hover:bg-rose-500/10 rounded"><Trash2 size={14} /></button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Projects */}
        {activeTab === 'projects' && (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="font-bold text-lg">Daftar Proyek</h3>
              {user.role === 'Maker' && (
                <button onClick={() => setShowAddProject(true)} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg text-sm font-bold">
                  <Plus size={14} /> Tambah Proyek
                </button>
              )}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {projects.map(project => {
                const client = clients.find(c => c.id === project.clientId);
                return (
                  <div key={project.id} className={`p-4 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                    <div className="flex justify-between items-start">
                      <div>
                        <h4 className="font-bold">{project.name}</h4>
                        <p className="text-sm text-slate-400">Klien: {client?.company}</p>
                      </div>
                      <span className={`px-2 py-0.5 rounded text-xs ${
                        project.status === 'Selesai' ? 'bg-emerald-500/20 text-emerald-400' : 
                        project.status === 'Sedang Berjalan' ? 'bg-blue-500/20 text-blue-400' : 'bg-amber-500/20 text-amber-400'
                      }`}>{project.status}</span>
                    </div>
                    <div className="mt-3">
                      <div className="flex justify-between text-sm mb-1">
                        <span>Progress</span>
                        <span>{project.progress}%</span>
                      </div>
                      <div className="w-full bg-slate-700 rounded-full h-2">
                        <div className="bg-indigo-500 h-2 rounded-full" style={{ width: `${project.progress}%` }}></div>
                      </div>
                      {user.role === 'Maker' && (
                        <input type="range" min="0" max="100" value={project.progress} onChange={(e) => handleProjectProgressChange(project.id, e.target.value)} className="w-full mt-2 accent-indigo-500" />
                      )}
                    </div>
                    <div className="flex justify-between mt-3 pt-2 border-t border-slate-700">
                      <span className="text-emerald-400 font-bold">{formatRupiah(project.value)}</span>
                      <span className="text-slate-400">{project.month}</span>
                      {user.role === 'Maker' && (
                        <button onClick={() => confirmDelete('project', project.id, project.name)} className="p-1 text-rose-400 hover:bg-rose-500/10 rounded"><Trash2 size={14} /></button>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Tasks Board */}
        {activeTab === 'tasks' && (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="font-bold text-lg">Papan Tugas</h3>
              {user.role === 'Maker' && (
                <button onClick={() => setShowAddTask(true)} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg text-sm font-bold">
                  <Plus size={14} /> Tambah Tugas
                </button>
              )}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              {['Harus Dikerjakan', 'Prioritas Utama', 'Sedang Berjalan', 'Selesai'].map(status => (
                <div key={status} className={`p-3 ${darkMode ? 'bg-slate-800' : 'bg-gray-100'} rounded-xl`}>
                  <div className="font-bold mb-2 pb-2 border-b border-slate-700">{status} ({tasks.filter(t => t.status === status).length})</div>
                  <div className="space-y-2">
                    {tasks.filter(t => t.status === status).map(task => (
                      <div key={task.id} className={`p-3 rounded-lg ${darkMode ? 'bg-slate-700' : 'bg-white'}`}>
                        <p className="font-semibold text-sm">{task.title}</p>
                        <div className="flex justify-between items-center mt-2 text-xs">
                          <span className="text-emerald-400">{formatRupiah(task.executorFee)}</span>
                          <span className="text-slate-400">{task.timeSpent} menit</span>
                        </div>
                        {task.status === 'Selesai' ? (
                          <div className="mt-2 text-center text-xs text-emerald-400">✓ Selesai oleh {task.assignedTo}</div>
                        ) : task.assignedTo ? (
                          task.assignedTo === user.name ? (
                            <button onClick={() => openCompleteTaskDialog(task.id)} className="w-full mt-2 py-1 bg-emerald-600 hover:bg-emerald-500 text-white text-xs font-bold rounded">Klaim & Selesai</button>
                          ) : (
                            <div className="mt-2 text-center text-xs text-slate-400">Dikerjakan {task.assignedTo}</div>
                          )
                        ) : (
                          <button onClick={() => handleClaimTask(task.id)} className="w-full mt-2 py-1 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-bold rounded">Ambil Kerja</button>
                        )}
                        {user.role === 'Maker' && task.status !== 'Selesai' && (
                          <button onClick={() => confirmDelete('task', task.id, task.title)} className="mt-2 text-rose-400 text-xs hover:underline">Hapus</button>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Finance */}
        {activeTab === 'finance' && (
          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className={`p-5 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                <p className="text-xs text-slate-400">Total Pendapatan</p>
                <p className="text-2xl font-bold text-emerald-400">{formatRupiah(stats.totalEarnings)}</p>
              </div>
              <div className={`p-5 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                <p className="text-xs text-slate-400">Total Fee Tim</p>
                <p className="text-2xl font-bold text-amber-400">{formatRupiah(stats.totalExecutorFees)}</p>
              </div>
              <div className={`p-5 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                <p className="text-xs text-slate-400">Laba Bersih</p>
                <p className="text-2xl font-bold text-indigo-400">{formatRupiah(stats.profit)}</p>
              </div>
            </div>
            <div className={`p-5 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
              <h3 className="font-bold mb-3">Laporan Tugas Selesai</h3>
              <div className="space-y-2">
                {tasks.filter(t => t.status === 'Selesai').map(task => (
                  <div key={task.id} className="flex justify-between items-center p-2 border-b border-slate-700">
                    <div>
                      <p className="font-medium">{task.title}</p>
                      <p className="text-xs text-slate-400">oleh {task.assignedTo} • {task.timeSpent} menit</p>
                    </div>
                    <span className="font-bold text-emerald-400">{formatRupiah(task.executorFee)}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Domains */}
        {activeTab === 'domains' && (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="font-bold text-lg">Monitoring Domain</h3>
              {user.role === 'Maker' && (
                <button onClick={() => setShowAddDomain(true)} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg text-sm font-bold">
                  <Plus size={14} /> Tambah Domain
                </button>
              )}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {domains.map(domain => {
                const daysLeft = Math.ceil((new Date(domain.expiryDate) - new Date()) / (1000 * 60 * 60 * 24));
                return (
                  <div key={domain.id} className={`p-4 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl border ${darkMode ? 'border-slate-700' : 'border-gray-200'}`}>
                    <div className="flex justify-between items-start">
                      <div>
                        <h4 className="font-bold font-mono">{domain.domainName}</h4>
                        <p className="text-sm text-slate-400">{domain.provider}</p>
                      </div>
                      <span className={`px-2 py-0.5 rounded text-xs ${daysLeft <= 30 ? 'bg-rose-500/20 text-rose-400' : 'bg-emerald-500/20 text-emerald-400'}`}>
                        {daysLeft > 0 ? `${daysLeft} hari` : 'EXPIRED'}
                      </span>
                    </div>
                    <div className="flex justify-between items-center mt-3 pt-2 border-t border-slate-700">
                      <div className="flex items-center gap-2">
                        <MousePointerClick size={14} className="text-sky-400" />
                        <span>{domain.clicks.toLocaleString()} klik</span>
                      </div>
                      <div className="flex items-center gap-2">
                        <Calendar size={14} className="text-slate-400" />
                        <span className="text-sm">{domain.expiryDate}</span>
                      </div>
                      {user.role === 'Maker' && (
                        <button onClick={() => confirmDelete('domain', domain.id, domain.domainName)} className="p-1 text-rose-400 hover:bg-rose-500/10 rounded"><Trash2 size={14} /></button>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </main>

      {/* Modals */}
      {showAddClient && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className={`${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl max-w-md w-full p-6`}>
            <h3 className="font-bold text-lg mb-4">Tambah Klien</h3>
            <form onSubmit={handleAddClientSubmit} className="space-y-3">
              <input type="text" required placeholder="Nama" value={newClient.name} onChange={(e) => setNewClient({...newClient, name: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="text" required placeholder="Perusahaan" value={newClient.company} onChange={(e) => setNewClient({...newClient, company: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="email" required placeholder="Email" value={newClient.email} onChange={(e) => setNewClient({...newClient, email: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="text" placeholder="Telepon" value={newClient.phone} onChange={(e) => setNewClient({...newClient, phone: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="number" placeholder="Total Deal" value={newClient.totalDeal} onChange={(e) => setNewClient({...newClient, totalDeal: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="number" placeholder="Sudah Dibayar" value={newClient.paidAmount} onChange={(e) => setNewClient({...newClient, paidAmount: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <button type="submit" className="w-full py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg font-bold">Simpan</button>
            </form>
          </div>
        </div>
      )}

      {showAddProject && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className={`${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl max-w-md w-full p-6`}>
            <h3 className="font-bold text-lg mb-4">Tambah Proyek</h3>
            <form onSubmit={handleAddProjectSubmit} className="space-y-3">
              <input type="text" required placeholder="Nama Proyek" value={newProject.name} onChange={(e) => setNewProject({...newProject, name: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <select required value={newProject.clientId} onChange={(e) => setNewProject({...newProject, clientId: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`}>
                <option value="">Pilih Klien</option>
                {clients.map(c => <option key={c.id} value={c.id}>{c.company}</option>)}
              </select>
              <input type="month" required value={newProject.month} onChange={(e) => setNewProject({...newProject, month: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="number" placeholder="Nilai Proyek" value={newProject.value} onChange={(e) => setNewProject({...newProject, value: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <button type="submit" className="w-full py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg font-bold">Simpan</button>
            </form>
          </div>
        </div>
      )}

      {showAddTask && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className={`${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl max-w-md w-full p-6`}>
            <h3 className="font-bold text-lg mb-4">Tambah Tugas</h3>
            <div className="mb-3">
              <p className="text-xs text-slate-400 mb-1">Preset Cepat:</p>
              <div className="grid grid-cols-2 gap-1">
                {TASK_PRESETS.map(preset => (
                  <button key={preset.id} type="button" onClick={() => selectPresetForNewTask(preset.id)} className="p-1 text-xs bg-slate-700 rounded hover:bg-indigo-600">{preset.label}</button>
                ))}
              </div>
            </div>
            <form onSubmit={handleAddTaskSubmit} className="space-y-3">
              <input type="text" required placeholder="Judul Tugas" value={newTask.title} onChange={(e) => setNewTask({...newTask, title: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <select required value={newTask.projectId} onChange={(e) => setNewTask({...newTask, projectId: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`}>
                <option value="">Pilih Proyek</option>
                {projects.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
              <input type="number" placeholder="Fee (Rp)" value={newTask.executorFee} onChange={(e) => setNewTask({...newTask, executorFee: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="number" placeholder="Estimasi Menit" value={newTask.timeSpent} onChange={(e) => setNewTask({...newTask, timeSpent: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="date" required placeholder="Due Date" value={newTask.dueDate} onChange={(e) => setNewTask({...newTask, dueDate: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <button type="submit" className="w-full py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg font-bold">Simpan</button>
            </form>
          </div>
        </div>
      )}

      {showAddDomain && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className={`${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl max-w-md w-full p-6`}>
            <h3 className="font-bold text-lg mb-4">Tambah Domain</h3>
            <form onSubmit={handleAddDomainSubmit} className="space-y-3">
              <input type="text" required placeholder="Domain Name" value={newDomain.domainName} onChange={(e) => setNewDomain({...newDomain, domainName: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="date" required placeholder="Expiry Date" value={newDomain.expiryDate} onChange={(e) => setNewDomain({...newDomain, expiryDate: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <input type="text" required placeholder="Provider" value={newDomain.provider} onChange={(e) => setNewDomain({...newDomain, provider: e.target.value})} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              <button type="submit" className="w-full py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg font-bold">Simpan</button>
            </form>
          </div>
        </div>
      )}

      {claimingTaskId && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className={`${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-xl max-w-sm w-full p-6`}>
            <h3 className="font-bold text-lg mb-2">Klaim Uang</h3>
            <div className="p-3 bg-emerald-500/20 rounded-lg text-center mb-4">
              <p className="text-xs text-emerald-400">Komisi Yang Didapat</p>
              <p className="text-xl font-bold">{formatRupiah(claimRewardValue)}</p>
            </div>
            <form onSubmit={handleCompleteTaskSubmit} className="space-y-3">
              <div>
                <label className="text-xs text-slate-400">Durasi Kerja (Menit)</label>
                <input type="number" required min="1" value={minutesSpentInput} onChange={(e) => {
                  setMinutesSpentInput(e.target.value);
                  const mins = Number(e.target.value) || 0;
                  const task = tasks.find(t => t.id === claimingTaskId);
                  if (task) setClaimRewardValue(Math.round((mins / task.timeSpent) * task.executorFee));
                }} className={`w-full p-2 rounded border ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-gray-100 border-gray-300'}`} />
              </div>
              <button type="submit" className="w-full py-2 bg-emerald-600 hover:bg-emerald-500 rounded-lg font-bold">Klaim & Selesai</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
